import React, { useState } from "react";
import { Link } from "react-scroll";
import "../styles.css"; // Import styles

const Navbar = () => {
  const [activeSection, setActiveSection] = useState("home");

  // Handle setting active section when clicked or scrolled into view
  const handleSetActive = (section) => {
    setActiveSection(section);
  };

  return (
    <nav className="navbar">
      <div className="navbar-logo">
        <img src="/logo.png" alt="Law Firm Logo" />
      </div>
      <ul className="navbar-links">
        {["home", "about", "practice", "professionals", "news", "gallery", "contact"].map((section) => (
          <li key={section}>
            <Link
              to={section}
              smooth={true}
              duration={500}
              onSetActive={() => handleSetActive(section)} // Set active on scroll or click
              className={activeSection === section ? "active" : ""} // Add active class
            >
              {section.replace(/^\w/, (c) => c.toUpperCase())}
            </Link>
          </li>
        ))}
      </ul>
    </nav>
  );
};

export default Navbar;
